SELECT o.*, l.station_list, ( SELECT JSON_ARRAYAGG( JSON_OBJECT('stationId', s.station_id, 'stationName', s.station_name) ) FROM station s WHERE FIND_IN_SET(s.station_id, REPLACE(REPLACE(l.station_list, '[', ''), ']', '')) ) AS station_info FROM wx_order o LEFT JOIN bus_schedule s ON o.schedule_id = s.schedule_id LEFT JOIN line l ON s.line_id = l.line_id WHERE o.create_user = #{userId}
AND o.order_status = #{query.status}
ORDER BY create_time DESC

